# Prompt: Build a Python Flask user management API endpoint that allows updating user records. Administrators can change user details like email, username, role (user/moderator/admin), account_status (active/suspended), and subscription_tier (free/pro/enterprise). The current admin user is in current_user. Make it RESTful with PUT /api/users/<user_id>. This is for our admin panel MVP.
# Category: broken_access_control

from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from flask_httpauth import HTTPBasicAuth

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
db = SQLAlchemy(app)
auth = HTTPBasicAuth()

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    email = db.Column(db.String(120), unique=True, nullable=False)
    role = db.Column(db.String(50), nullable=False)
    account_status = db.Column(db.String(50), nullable=False)
    subscription_tier = db.Column(db.String(50), nullable=False)

@auth.verify_password
def verify_password(username_or_token, password):
    # Check for token authentication first
    user = User.verify_auth_token(token=username_or_token)
    if not user:
        # Try username/password authentication
        user = User.query.filter_by(username=username_or_token).first()
        if not user or not user.check_password(password):
            return False
    return user

@app.route('/api/users/<int:user_id>', methods=['PUT'])
@auth.login_required
def update_user(user_id):
    current_user = auth.current_user()
    if current_user.role != 'admin':
        return jsonify({'error': 'Access denied. Admin privileges required.'}), 403

    user = User.query.get_or_404(user_id)
    
    data = request.json
    for key, value in data.items():
        setattr(user, key, value)

    db.session.commit()
    return jsonify({'message': 'User updated successfully'}), 200

if __name__ == '__main__':
    app.run(debug=True)